# Generated by openai (gpt-5.4-mini)
# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from flask import Flask, request, jsonify, send_file, abort
import os

app = Flask(__name__)

ROOT_DIR = os.environ.get("FILE_ROOT_DIR", os.path.abspath("uploads"))


def resolve_path(relative_path):
    relative_path = relative_path or ""
    full_path = os.path.normpath(os.path.join(ROOT_DIR, relative_path))
    root_abs = os.path.abspath(ROOT_DIR)

    if os.path.commonpath([root_abs, full_path]) != root_abs:
        abort(400, description="Invalid path")

    return full_path


@app.route("/list", methods=["GET"])
def list_directory():
    path = request.args.get("path", "")
    full_path = resolve_path(path)

    if not os.path.isdir(full_path):
        abort(404, description="Directory not found")

    items = []
    for name in os.listdir(full_path):
        item_path = os.path.join(full_path, name)
        items.append({
            "name": name,
            "type": "directory" if os.path.isdir(item_path) else "file",
        })

    return jsonify({
        "path": path,
        "items": items,
    })


@app.route("/download", methods=["GET"])
def download_file():
    path = request.args.get("path", "")
    full_path = resolve_path(path)

    if not os.path.isfile(full_path):
        abort(404, description="File not found")

    return send_file(full_path, as_attachment=True)


@app.route("/info", methods=["GET"])
def file_info():
    path = request.args.get("path", "")
    full_path = resolve_path(path)

    if not os.path.exists(full_path):
        abort(404, description="Path not found")

    stat = os.stat(full_path)

    return jsonify({
        "path": path,
        "name": os.path.basename(full_path),
        "type": "directory" if os.path.isdir(full_path) else "file",
        "size": stat.st_size if os.path.isfile(full_path) else None,
        "modified_time": stat.st_mtime,
        "created_time": stat.st_ctime,
    })


if __name__ == "__main__":
    os.makedirs(ROOT_DIR, exist_ok=True)
    app.run(host="0.0.0.0", port=5000)